import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer, CloudLightning } from 'lucide-react';
import './App.css';

const API_KEY = "1d30e0668b384c4d133dc45fe617b03b"; 

function App() {
  const [city, setCity] = useState('Visnagar');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

    } catch (err) {
      setError('સિટી મળ્યું નથી! ફરીથી ટ્રાય કરો.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  const getWeatherIcon = (main, size = 50) => {
    switch (main) {
      case 'Clear': return <Sun className="icon-glow text-sun" size={size} />;
      case 'Clouds': return <Cloud className="icon-glow text-cloud" size={size} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="icon-glow text-rain" size={size} />;
      case 'Thunderstorm': return <CloudLightning className="icon-glow text-thunder" size={size} />;
      default: return <Sun className="icon-glow text-sun" size={size} />;
    }
  };

  return (
    <div className="app-container">
      <div className="weather-card">

        {/* Advanced Search Bar */}
        <form onSubmit={handleSearch} className="search-form">
          <input 
            type="text" 
            placeholder="સર્ચ કરો..." 
            value={city}
            onChange={(e) => setCity(e.target.value)}
          />
          <button type="submit"><Search size={18} /></button>
        </form>

        {loading && <div className="status-msg">ડેટા લોડ થઈ રહ્યો છે...</div>}
        {error && <div className="status-msg error">{error}</div>}

        {/* Main Dashboard UI */}
        {weatherData && !loading && !error && (
          <div className="main-weather">
            <h2 className="location">{weatherData.name}, {weatherData.sys.country}</h2>

            <div className="weather-info-block">
              {getWeatherIcon(weatherData.weather[0].main, 70)}
              <h1 className="temp">{Math.round(weatherData.main.temp)}°C</h1>
            </div>

            <p className="description">{weatherData.weather[0].description.toUpperCase()}</p>

            {/* Advanced Stats Row */}
            <div className="stats-row">
              <div className="stat-box">
                <Thermometer size={18} className="stat-icon" />
                <span className="stat-label">Feels like</span>
                <span className="stat-value">{Math.round(weatherData.main.feels_like)}°C</span>
              </div>
              <div className="stat-box">
                <Droplets size={18} className="stat-icon" />
                <span className="stat-label">Humidity</span>
                <span className="stat-value">{weatherData.main.humidity}%</span>
              </div>
              <div className="stat-box">
                <Wind size={18} className="stat-icon" />
                <span className="stat-label">Wind</span>
                <span className="stat-value">{weatherData.wind.speed} m/s</span>
              </div>
            </div>

            {/* Future Forecast Section */}
            <h3 className="forecast-title">આગામી દિવસોની આગાહી</h3>
            <div className="forecast-container">
              {forecastData.map((day, idx) => (
                <div key={idx} className="forecast-item">
                  <span className="forecast-date">
                    {new Date(day.dt * 1000).toLocaleDateString('en-US', { weekday: 'short' })}
                  </span>
                  <div className="forecast-icon-wrapper">
                    {getWeatherIcon(day.weather[0].main, 28)}
                  </div>
                  <span className="forecast-temp">{Math.round(day.main.temp)}°C</span>
                </div>
              ))}
            </div>

          </div>
        )}
      </div>
    </div>
  );
}

export default App;
